from concurrent import futures
import grpc
from envoy.service.auth.v2 import auth_pb2
from envoy.service.auth.v2 import auth_pb2_grpc
from envoy.api.v2.core import base_pb2
from google.protobuf import any_pb2
from google.rpc import status_pb2

class AuthService(auth_pb2_grpc.AuthorizationServicer):
    def Check(self, request, context):
        headers = dict((header.key, header.value) for header in request.attributes.request.http.headers)
        
        # Check for a specific header and make authorization decision:
        auth_token = headers.get('x-api-key')
        if auth_token == "authorized":
            return auth_pb2.CheckResponse(
                status=status_pb2.Status(code=0),
                ok_response=auth_pb2.OkHttpResponse(
                    headers=[
                        base_pb2.HeaderValueOption(
                            header=base_pb2.HeaderValue(key="x-additional-header", value="additional header value")
                        )
                    ]
                )
            )

        return auth_pb2.CheckResponse(
            status=status_pb2.Status(code=16, message='Unauthorised'),  # Code 16 signifies unauthorised
            denied_response=auth_pb2.DeniedHttpResponse(
                status=base_pb2.HttpStatus(code=base_pb2.HttpStatusCode.Value('Unauthorized')),
                body="Invalid API Key"
            )
        )


def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    auth_pb2_grpc.add_AuthorizationServicer_to_server(AuthService(), server)
    server.add_insecure_port('[::]:9090')
    server.start()
    server.wait_for_termination()

if __name__ == "__main__":
    serve()